(function(){'use strict';var COPY_ICON_SVG='<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>';var CHECK_ICON_SVG='<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="20 6 9 17 4 12"></polyline></svg>';function getLanguage(highlightDiv){const lang=highlightDiv.dataset.lang||'';return lang==='text'?'':lang;}
function copyToClipboard(text,onSuccess){if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(text).then(onSuccess).catch(function(){fallbackCopy(text,onSuccess);});}else{fallbackCopy(text,onSuccess);}}
function fallbackCopy(text,onSuccess){const textarea=document.createElement('textarea');textarea.value=text;textarea.style.position='fixed';textarea.style.opacity='0';document.body.appendChild(textarea);textarea.select();try{document.execCommand('copy');onSuccess();}catch(_err){}
document.body.removeChild(textarea);}
function setupCodeBlock(highlightDiv){const pre=highlightDiv.querySelector('pre');if(!pre){return;}
const language=getLanguage(highlightDiv);const header=document.createElement('div');header.className='code-block-header';const langLabel=document.createElement('span');langLabel.className='code-block-lang';langLabel.textContent=language;langLabel.setAttribute('aria-hidden','true');header.appendChild(langLabel);const copyButton=document.createElement('button');copyButton.className='code-block-copy';copyButton.setAttribute('type','button');copyButton.setAttribute('aria-label','Copy code to clipboard');copyButton.innerHTML=COPY_ICON_SVG;copyButton.addEventListener('click',function(){const text=pre.textContent||'';copyToClipboard(text,function(){copyButton.innerHTML=CHECK_ICON_SVG;copyButton.classList.add('copied');setTimeout(function(){copyButton.innerHTML=COPY_ICON_SVG;copyButton.classList.remove('copied');},2000);});});header.appendChild(copyButton);highlightDiv.insertBefore(header,pre);}
function setupAllCodeBlocks(){document.querySelectorAll('.highlight').forEach(setupCodeBlock);}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',setupAllCodeBlocks);}else{setupAllCodeBlocks();}})();